CREATE OR REPLACE FUNCTION public.limpar_nome_produto_spot(p_name text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public'
AS $function$
DECLARE
    v_pos INTEGER;
BEGIN
    IF p_name IS NULL OR p_name = '' THEN
        RETURN p_name;
    END IF;
    
    v_pos := POSITION('. ' IN p_name);
    
    IF v_pos > 0 THEN
        RETURN SUBSTRING(p_name FROM v_pos + 2);
    END IF;
    
    RETURN p_name;
END;
$function$;
